# scripts/check-doc-completeness.py
import pathlib, sys

REQUIRED_DOCS = {
    "runbook": pathlib.Path("docs/runbook.md"),
    "getting_started": pathlib.Path("docs/getting-started.md"),
    "adr_directory": pathlib.Path("docs/adr/"),
}

RUNBOOK_REQUIRED_SECTIONS = [
    "## High error rate",
    "## Budget exceeded",
    "## Rollback",
    "Dashboard:",
    "On-call rotation:",
]

def check_runbook(path: pathlib.Path) -> list[str]:
    if not path.exists():
        return [f"Runbook missing at {path}"]
    content = path.read_text()
    missing = [s for s in RUNBOOK_REQUIRED_SECTIONS if s not in content]
    return [f"Runbook missing required section: {s!r}" for s in missing]

def check_adr_directory(path: pathlib.Path) -> list[str]:
    if not path.exists() or not list(path.glob("*.md")):
        return [f"No ADR files found in {path}. At least one ADR is required."]
    return []

def main():
    failures = []
    failures += check_runbook(REQUIRED_DOCS["runbook"])
    failures += check_adr_directory(REQUIRED_DOCS["adr_directory"])
    if not REQUIRED_DOCS["getting_started"].exists():
        failures.append(f"Getting-started guide missing at {REQUIRED_DOCS['getting_started']}")
    if failures:
        for f in failures:
            print(f"BLOCK: {f}")
        sys.exit(1)
    print("Documentation completeness check passed.")

if __name__ == "__main__":
    main()
